## Animations

SwiftUI makes it easy to add beautiful animations to your app:

```swift
struct AnimatedView: View {
    @State private var isExpanded = false

    var body: some View {
        VStack {
            Button(

) {
                withAnimation(.spring()) {
                    isExpanded.toggle()
                }
            }

            if isExpanded {
                Rectangle()
                    .fill(Color.blue)
                    .frame(height: 200)
                    .transition(.scale)
            }
        }
    }
}
```

## Custom View Modifiers

Create reusable view modifiers to keep your code DRY:

```swift
struct CardModifier: ViewModifier {
    func body(content: Content) -> some View {
        content
            .padding()
            .background(Color.white)
            .cornerRadius(10)
            .shadow(radius: 5)
    }
}

extension View {
    func cardStyle() -> some View {
        self.modifier(CardModifier())
    }
}

